        if let Err(e) = self
            .registry
            .update_account_config(account_id, config)
            .await
        {
            warn!(error = %e, account_id, channel_type = channel_type.as_str(), "failed to hot-update config");
        }

        info!(
            account_id,
            identifier,
            channel_type = channel_type.as_str(),
            "sender denied"
        );
        Ok(serde_json::json!({
            "denied": identifier,
            "type": channel_type.to_string()
        }))
    }
}

